#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < M; i++) {
        char C;
        int K;
        char X;
        scanf(" %c %d %c", &C, &K, &X);
        int count = 0;
        for (int j = 0; j < N; j++) {
            for (int k = j; k < N; k++) {
                int max = A[j];
                for (int l = j; l <= k; l++) {
                    if (A[l] > max) {
                        max = A[l];
                    }
                }
                if ((C == '>' && max > K) || (C == '<' && max < K) || (C == '=' && max == K)) {
                    count++;
                }
            }
        }
        if ((count % 2 == 1 && X == 'D') || (count % 2 == 0 && X == 'C')) {
            printf("D");
        } else {
            printf("C");
        }
    }
    return 0;
}

