        int M = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        for (int i = 0; i < M; i++) {
            char C = sc.next().charAt(0);
            int K = sc.nextInt();
            char X = sc.next().charAt(0);
            int count = 0;
            for (int j = 0; j < N; j++) {
                for (int k = j; k < N; k++) {
                    int max = A[j];
                    for (int l = j; l <= k; l++) {
                        if (A[l] > max) {
                            max = A[l];
                        }
                    }
                    if ((C == '>' && max > K) || (C == '<' && max < K) || (C == '=' && max == K)) {
